# Echo/Reverb buffer - circular buffer for delay
MAX_DELAY_SECONDS = 2.0
MAX_DELAY_SAMPLES = int(MAX_DELAY_SECONDS * SAMPLE_RATE)


class EchoProcessor:
    def __init__(self):
        self.delay_samples = int(0.3 * SAMPLE_RATE)  # 300ms default delay
        self.decay = 0.5  # Echo decay factor
        self.wet_mix = 0.5  # Wet/dry mix
        self.num_echoes = 3  # Number of echo repetitions
        self.reverb_enabled = True

        # Circular buffer for delay line
        self.delay_buffer = np.zeros(MAX_DELAY_SAMPLES, dtype=np.float32)
        self.write_pos = 0
        self.lock = threading.Lock()

        # Multi-tap delay buffers for reverb
        self.reverb_buffers = [
            np.zeros(MAX_DELAY_SAMPLES, dtype=np.float32) for _ in range(4)
        ]
        self.reverb_write_pos = 0

        # Reverb parameters (Schroeder reverb)
        self.reverb_delays = [1557, 1617, 1491, 1422]  # in samples
        self.reverb_decay = 0.7

        # All-pass filter buffers
        self.allpass_buffers = [
            np.zeros(500, dtype=np.float32),
            np.zeros(300, dtype=np.float32)
        ]
        self.allpass_pos = [0, 0]
        self.allpass_delays = [347, 113]
        self.allpass_gain = 0.7

    def set_delay(self, delay_ms):
        with self.lock:
            self.delay_samples = int((delay_ms / 1000.0) * SAMPLE_RATE)
            self.delay_samples = min(self.delay_samples, MAX_DELAY_SAMPLES - 1)

    def set_decay(self, decay):
        with self.lock:
            self.decay = float(decay)

    def set_wet_mix(self, wet):
        with self.lock:
            self.wet_mix = float(wet)

    def set_num_echoes(self, n):
        with self.lock:
            self.num_echoes = int(n)

    def set_reverb_decay(self, decay):
        with self.lock:
            self.reverb_decay = float(decay)

    def process_echo(self, input_signal):
        """Apply multi-tap echo effect"""
        output = np.zeros_like(input_signal)

        for i, sample in enumerate(input_signal):
            # Write to delay buffer
            self.delay_buffer[self.write_pos] = sample

            # Read multiple echoes
            echo_sum = 0.0
            for echo_num in range(1, self.num_echoes + 1):
                read_pos = (self.write_pos - echo_num * self.delay_samples) % MAX_DELAY_SAMPLES
                echo_sum += self.delay_buffer[read_pos] * (self.decay ** echo_num)

            # Mix dry and wet signals
            output[i] = (1.0 - self.wet_mix) * sample + self.wet_mix * echo_sum

            self.write_pos = (self.write_pos + 1) % MAX_DELAY_SAMPLES

        return output

    def process_reverb(self, input_signal):
        """Apply Schroeder reverb using comb filters + all-pass filters"""
        output = np.zeros_like(input_signal)

        for i, sample in enumerate(input_signal):
            # Comb filters (parallel)
            comb_sum = 0.0
            for buf_idx, (buf, delay) in enumerate(zip(self.reverb_buffers, self.reverb_delays)):
                read_pos = (self.reverb_write_pos - delay) % MAX_DELAY_SAMPLES
                delayed = buf[read_pos]
                buf[self.reverb_write_pos] = sample + delayed * self.reverb_decay
                comb_sum += delayed

            self.reverb_write_pos = (self.reverb_write_pos + 1) % MAX_DELAY_SAMPLES

            # All-pass filters (series)
            ap_input = comb_sum / 4.0
            for ap_idx in range(2):
                buf = self.allpass_buffers[ap_idx]
                delay = self.allpass_delays[ap_idx]
                pos = self.allpass_pos[ap_idx]

                read_pos = (pos - delay) % len(buf)
                delayed = buf[read_pos]
                buf[pos] = ap_input + delayed * self.allpass_gain
                ap_input = -self.allpass_gain * ap_input + delayed

                self.allpass_pos[ap_idx] = (pos + 1) % len(buf)

            output[i] = (1.0 - self.wet_mix) * sample + self.wet_mix * ap_input

        return output

    def process(self, input_signal):
        """Main processing function"""
        with self.lock:
            if self.reverb_enabled:
                return self.process_reverb(input_signal)
            else:
                return self.process_echo(input_signal)


