    def create_slider(self, parent, label, name, min_val, max_val, default, command, unit, bg, resolution=1):
        frame = tk.Frame(parent, bg=bg, pady=5)
        frame.pack(fill='x')

        # Label row
        label_frame = tk.Frame(frame, bg=bg)
        label_frame.pack(fill='x')

        tk.Label(
            label_frame,
            text=label,
            font=('Helvetica', 10),
            bg=bg,
            fg='white'
        ).pack(side='left')

        value_var = tk.StringVar(value=f"{default}{unit}")
        tk.Label(
            label_frame,
            textvariable=value_var,
            font=('Helvetica', 10, 'bold'),
            bg=bg,
            fg='#e94560'
        ).pack(side='right')

        # Store value var
        setattr(self, f"{name}_var", value_var)
        setattr(self, f"{name}_unit", unit)

        # Slider
        slider = tk.Scale(
            frame,
            from_=min_val,
            to=max_val,
            orient='horizontal',
            resolution=resolution,
            command=lambda v, cmd=command, var=value_var, u=unit: self.slider_callback(v, cmd, var, u),
            bg=bg,
            fg='white',
            troughcolor='#0f3460',
            activebackground='#e94560',
            highlightthickness=0,
            showvalue=False
        )
        slider.set(default)
        slider.pack(fill='x')

        setattr(self, f"{name}_slider", slider)

    def slider_callback(self, value, command, value_var, unit):
        try:
            val = float(value)
            if unit == "":
                value_var.set(f"{val:.2f}")
            else:
                value_var.set(f"{int(val)}{unit}")
        except:
            pass
        command(value)

    def on_mode_change(self):
        mode = self.mode_var.get()
        self.processor.reverb_enabled = (mode == "reverb")
        print(f"Mode changed to: {mode}")

    def on_delay_change(self, value):
        self.processor.set_delay(float(value))

    def on_decay_change(self, value):
        self.processor.set_decay(float(value))

    def on_wet_change(self, value):
        self.processor.set_wet_mix(float(value))

    def on_echoes_change(self, value):
        self.processor.set_num_echoes(int(float(value)))

    def on_reverb_decay_change(self, value):
        self.processor.set_reverb_decay(float(value))

    def audio_callback(self, indata, outdata, frames, time, status):
        if status:
            print(f"Audio status: {status}")

        # Get mono input
        input_signal = indata[:, 0].copy().astype(np.float32)

        # Update level for VU meter
        self.current_level = float(np.max(np.abs(input_signal)))

        # Process audio
        processed = self.processor.process(input_signal)

        # Clip to prevent distortion
        processed = np.clip(processed, -1.0, 1.0)

        # Output (mono to all channels)
        for ch in range(outdata.shape[1]):
            outdata[:, ch] = processed

    def start_audio(self):
        if self.is_running:
            return

        try:
            # Get default devices
            default_input = sd.default.device[0]
            default_output = sd.default.device[1]

            print(f"Starting audio stream...")
            print(f"Input device: {sd.query_devices(default_input)['name']}")
            print(f"Output device: {sd.query_devices(default_output)['name']}")

            self.stream = sd.Stream(
                samplerate=SAMPLE_RATE,
                blocksize=BLOCK_SIZE,
                dtype=np.float32,
                channels=CHANNELS,
                callback=self.audio_callback,
                latency='low'
            )
            self.stream.start()
            self.is_running = True

            self.start_btn.config(state='disabled')
            self.stop_btn.config(state='normal')
            self.status_var.set("🟢 Running")
            self.status_label.config(fg='#27ae60')

            print("✅ Audio stream started successfully!")
            print("🎙️ Speak into your microphone to hear the echo/reverb effect")

        except Exception as e:
            print(f"❌ Error starting audio: {e}")
            self.status_var.set(f"❌ Error: {str(e)[:30]}")
            self.status_label.config(fg='#e74c3c')

    def stop_audio(self):
        if not self.is_running:
            return

        try:
            if self.stream:
                self.stream.stop()
                self.stream.close()
                self.stream = None

            self.is_running = False
            self.start_btn.config(state='normal')
            self.stop_btn.config(state='disabled')
            self.status_var.set("⚫ Stopped")
            self.status_label.config(fg='#a8a8b3')
            self.current_level = 0.0

            print("⏹️ Audio stream stopped")

        except Exception as e:
            print(f"Error stopping audio: {e}")

    def update_vu_meter(self):
        """Update VU meter display"""
        try:
            canvas = self.vu_canvas
            width = canvas.winfo_width()
            height = canvas.winfo_height()

            if width > 1:
                canvas.delete('all')

                # Background
                canvas.create_rectangle(0, 0, width, height, fill='#0a0a0a', outline='')

                # Level bar
                level = min(self.current_level, 1.0)
                bar_width = int(level * width)

                if bar_width > 0:
                    # Color gradient: green -> yellow -> red
                    if level < 0.6:
                        color = '#27ae60'
                    elif level < 0.8:
                        color = '#f39c12'
                    else:
                        color = '#e74c3c'

                    canvas.create_rectangle(0, 2, bar_width, height - 2, fill=color, outline='')

                # Grid lines
                for i in range(1, 10):
                    x = int(i * width / 10)
                    canvas.create_line(x, 0, x, height, fill='#333333', width=1)

                # Labels
                canvas.create_text(5, height // 2, text="-∞", fill='#666666', font=('Helvetica', 7), anchor='w')
                canvas.create_text(width - 5, height // 2, text="0dB", fill='#666666', font=('Helvetica', 7),
                                   anchor='e')

        except Exception:
            pass

        self.root.after(50, self.update_vu_meter)

    def on_closing(self):
        print("Closing application...")
        self.stop_audio()
        self.root.destroy()


